import{_ as p,H as s,f as n,i as e}from"./chunks/framework.DLd0CbzH.js";const u=JSON.parse('{"title":"性能优化","description":"","frontmatter":{},"headers":[],"relativePath":"interview/micro.md","filePath":"interview/micro.md","lastUpdated":null}'),i={name:"interview/micro.md"};function t(l,a,o,r,d,h){return s(),n("div",null,[...a[0]||(a[0]=[e(`<h2 id="_1-什么是微前端-为什么要做微前端" tabindex="-1"><strong>1. 什么是微前端？为什么要做微前端？</strong> <a class="header-anchor" href="#_1-什么是微前端-为什么要做微前端" aria-label="Permalink to &quot;**1. 什么是微前端？为什么要做微前端？**&quot;">​</a></h2><h3 id="标准回答" tabindex="-1"><strong>标准回答</strong> <a class="header-anchor" href="#标准回答" aria-label="Permalink to &quot;**标准回答**&quot;">​</a></h3><p>微前端（Micro Frontends）是一种将大型前端单体应用拆分成多个可独立开发、独立部署、独立运行子应用的架构模式，其思想来源于后端微服务。</p><p>它的核心目标不是“拆项目”，而是解决大型前端工程在多人协作、技术演进和部署效率上的问题。</p><p>比如一个大型中后台系统，可以拆成：</p><ul><li>用户中心</li><li>权限中心</li><li>商品中心</li><li>订单中心</li><li>营销中心</li></ul><p>每个业务模块由不同团队独立维护，彼此低耦合。</p><h3 id="微前端解决的问题" tabindex="-1"><strong>微前端解决的问题</strong> <a class="header-anchor" href="#微前端解决的问题" aria-label="Permalink to &quot;**微前端解决的问题**&quot;">​</a></h3><p>在大型项目中，传统单体前端会遇到几个明显问题：</p><h4 id="_1-多人协作冲突严重" tabindex="-1"><strong>（1）多人协作冲突严重</strong> <a class="header-anchor" href="#_1-多人协作冲突严重" aria-label="Permalink to &quot;**（1）多人协作冲突严重**&quot;">​</a></h4><p>几十名前端同时开发一个仓库，容易出现：</p><ul><li>Git 冲突频繁</li><li>发版互相影响</li><li>测试范围不可控</li></ul><p>一次发布可能影响全站。</p><p>微前端拆分后：</p><p>每个子应用独立开发、独立上线。</p><p>即使订单系统发布失败，也不会影响用户系统。</p><hr><h4 id="_2-技术栈升级困难" tabindex="-1"><strong>（2）技术栈升级困难</strong> <a class="header-anchor" href="#_2-技术栈升级困难" aria-label="Permalink to &quot;**（2）技术栈升级困难**&quot;">​</a></h4><p>例如旧项目使用：</p><ul><li>AngularJS</li><li>Vue2</li></ul><p>但新业务需要：</p><ul><li>React18</li><li>Vue3</li></ul><p>如果是单体架构：</p><p>升级成本极高。</p><p>而微前端允许：</p><p>新模块逐步迁移。</p><p>例如：</p><ul><li>老模块继续运行 Vue2</li><li>新模块使用 React18</li></ul><p>实现渐进式升级。</p><hr><h4 id="_3-构建速度和维护成本问题" tabindex="-1"><strong>（3）构建速度和维护成本问题</strong> <a class="header-anchor" href="#_3-构建速度和维护成本问题" aria-label="Permalink to &quot;**（3）构建速度和维护成本问题**&quot;">​</a></h4><p>大型项目：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>500+ 页面</span></span>
<span class="line"><span>几十万行代码</span></span></code></pre></div><p>每次构建可能十几分钟。</p><p>微前端后：</p><p>子系统单独构建。</p><p>提升 CI/CD 效率。</p><hr><h2 id="_2-微前端有哪些实现方案" tabindex="-1"><strong>2. 微前端有哪些实现方案？</strong> <a class="header-anchor" href="#_2-微前端有哪些实现方案" aria-label="Permalink to &quot;**2. 微前端有哪些实现方案？**&quot;">​</a></h2><h3 id="_1-iframe-方案" tabindex="-1"><strong>（1）iframe 方案</strong> <a class="header-anchor" href="#_1-iframe-方案" aria-label="Permalink to &quot;**（1）iframe 方案**&quot;">​</a></h3><p>最简单直接。</p><p>把子系统放进 iframe：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;iframe src=&quot;/user-system&quot;&gt;&lt;/iframe&gt;</span></span></code></pre></div><p>优点：</p><ul><li>完全隔离</li><li>技术栈独立</li><li>实现简单</li></ul><p>缺点也明显：</p><ul><li>通信困难</li><li>路由管理麻烦</li><li>用户体验差</li><li>SEO 不友好</li></ul><p>所以：</p><p>通常不作为核心业务方案。</p><p>更多用于第三方系统接入。</p><hr><h3 id="_2-路由分发式" tabindex="-1"><strong>（2）路由分发式</strong> <a class="header-anchor" href="#_2-路由分发式" aria-label="Permalink to &quot;**（2）路由分发式**&quot;">​</a></h3><p>通过 Nginx 或网关：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/user → React 应用</span></span>
<span class="line"><span>/order → Vue 应用</span></span></code></pre></div><p>优点：</p><ul><li>简单稳定</li><li>易于落地</li></ul><p>缺点：</p><p>不能真正做到应用共存。</p><p>本质还是多个 SPA。</p><hr><h3 id="_3-web-components" tabindex="-1"><strong>（3）Web Components</strong> <a class="header-anchor" href="#_3-web-components" aria-label="Permalink to &quot;**（3）Web Components**&quot;">​</a></h3><p>利用浏览器原生能力：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>customElements.define()</span></span></code></pre></div><p>实现组件隔离。</p><p>优点：</p><ul><li>天然样式隔离</li><li>技术栈无关</li></ul><p>缺点：</p><ul><li>生态成熟度一般</li><li>学习成本较高</li></ul><p>企业落地不多。</p><hr><h3 id="_4-js-entry-主流方案" tabindex="-1"><strong>（4）JS Entry（主流方案）</strong> <a class="header-anchor" href="#_4-js-entry-主流方案" aria-label="Permalink to &quot;**（4）JS Entry（主流方案）**&quot;">​</a></h3><p>目前企业最常见。</p><p>代表框架：</p><p>qiankun</p><p>核心思想：</p><p>主应用动态加载子应用资源。</p><p>主应用负责：</p><ul><li>路由分发</li><li>生命周期管理</li><li>沙箱隔离</li></ul><p>子应用：</p><p>独立运行。</p><p>这是目前大型中后台系统最主流的方案。</p><hr><h3 id="_5-module-federation" tabindex="-1"><strong>（5）Module Federation</strong> <a class="header-anchor" href="#_5-module-federation" aria-label="Permalink to &quot;**（5）Module Federation**&quot;">​</a></h3><p>来自：</p><p>Webpack 5。</p><p>它的核心不是“应用拆分”，而是：</p><p>模块共享。</p><p>例如：</p><p>多个系统共用：</p><ul><li>React</li><li>组件库</li><li>工具函数</li></ul><p>避免重复打包。</p><p>所以：</p><p>qiankun 更偏应用级微前端。<br> Module Federation 更偏模块级共享。</p><p>很多企业会组合使用。</p><hr><h2 id="_3-qiankun-原理是什么" tabindex="-1"><strong>3. qiankun 原理是什么？</strong> <a class="header-anchor" href="#_3-qiankun-原理是什么" aria-label="Permalink to &quot;**3. qiankun 原理是什么？**&quot;">​</a></h2><h3 id="核心回答" tabindex="-1"><strong>核心回答</strong> <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;**核心回答**&quot;">​</a></h3><p>qiankun 的底层核心：</p><p><strong>single-spa + import-html-entry</strong></p><p>它主要做了四件事：</p><h3 id="第一-路由劫持" tabindex="-1"><strong>第一：路由劫持</strong> <a class="header-anchor" href="#第一-路由劫持" aria-label="Permalink to &quot;**第一：路由劫持**&quot;">​</a></h3><p>监听：</p><ul><li>hashchange</li><li>popstate</li></ul><p>当 URL 变化时：</p><p>判断当前应该激活哪个子应用。</p><p>例如：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/order/*</span></span></code></pre></div><p>激活订单系统。</p><hr><h3 id="第二-动态资源加载" tabindex="-1"><strong>第二：动态资源加载</strong> <a class="header-anchor" href="#第二-动态资源加载" aria-label="Permalink to &quot;**第二：动态资源加载**&quot;">​</a></h3><p>主应用请求子应用 HTML。</p><p>解析其中：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>script</span></span>
<span class="line"><span>link</span></span>
<span class="line"><span>style</span></span></code></pre></div><p>然后动态执行 JS。</p><p>本质类似：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import()</span></span></code></pre></div><p>动态加载资源。</p><p>所以：</p><p>子应用不需要提前打包进主应用。</p><hr><h3 id="第三-生命周期管理" tabindex="-1"><strong>第三：生命周期管理</strong> <a class="header-anchor" href="#第三-生命周期管理" aria-label="Permalink to &quot;**第三：生命周期管理**&quot;">​</a></h3><p>每个子应用必须导出：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bootstrap</span></span>
<span class="line"><span>mount</span></span>
<span class="line"><span>unmount</span></span></code></pre></div><p>作用分别是：</p><ul><li>bootstrap：初始化</li><li>mount：挂载应用</li><li>unmount：卸载应用</li></ul><p>主应用负责统一调度。</p><p>这也是为什么：</p><p>子应用可独立运行，也能嵌入运行。</p><hr><h3 id="第四-沙箱隔离" tabindex="-1"><strong>第四：沙箱隔离</strong> <a class="header-anchor" href="#第四-沙箱隔离" aria-label="Permalink to &quot;**第四：沙箱隔离**&quot;">​</a></h3><p>避免子应用污染全局环境。</p><p>比如：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>window.a = 1</span></span></code></pre></div><p>不能影响其他子应用。</p><p>因此 qiankun 提供：</p><ul><li>JS 沙箱</li><li>CSS 隔离</li></ul><hr><h2 id="_4-qiankun-沙箱隔离原理" tabindex="-1"><strong>4. qiankun 沙箱隔离原理？</strong> <a class="header-anchor" href="#_4-qiankun-沙箱隔离原理" aria-label="Permalink to &quot;**4. qiankun 沙箱隔离原理？**&quot;">​</a></h2><p><strong>这是高频深挖题。</strong></p><p><strong>qiankun 主要有两种沙箱：</strong></p><h3 id="_1-snapshotsandbox" tabindex="-1"><strong>（1）SnapshotSandbox</strong> <a class="header-anchor" href="#_1-snapshotsandbox" aria-label="Permalink to &quot;**（1）SnapshotSandbox**&quot;">​</a></h3><p>快照沙箱。</p><p>原理：</p><p>进入应用前保存：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>window</span></span></code></pre></div><p>退出时恢复。</p><p>类似：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Object.assign()</span></span></code></pre></div><p>优点：简单。</p><p>缺点：性能差。</p><p><strong>现在基本不用。</strong></p><hr><h3 id="_2-proxysandbox-主流" tabindex="-1"><strong>（2）ProxySandbox（主流）</strong> <a class="header-anchor" href="#_2-proxysandbox-主流" aria-label="Permalink to &quot;**（2）ProxySandbox（主流）**&quot;">​</a></h3><p>基于：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy</span></span></code></pre></div><p>代理：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>window</span></span></code></pre></div><p>例如：</p><p>子应用执行：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>window.test = 1</span></span></code></pre></div><p>实际上写入的是代理对象。</p><p>退出应用：直接销毁代理，不会污染全局。</p><p>这是当前主流方案。</p><hr><h2 id="_5-微前端如何做应用通信" tabindex="-1"><strong>5. 微前端如何做应用通信？</strong> <a class="header-anchor" href="#_5-微前端如何做应用通信" aria-label="Permalink to &quot;**5. 微前端如何做应用通信？**&quot;">​</a></h2><p>常见方案有五种。</p><h3 id="props-传值" tabindex="-1"><strong>props 传值</strong> <a class="header-anchor" href="#props-传值" aria-label="Permalink to &quot;**props 传值**&quot;">​</a></h3><p>主应用注册时：传递参数。</p><p>适合：父子关系简单场景。</p><hr><h3 id="全局状态管理" tabindex="-1"><strong>全局状态管理</strong> <a class="header-anchor" href="#全局状态管理" aria-label="Permalink to &quot;**全局状态管理**&quot;">​</a></h3><p>qiankun：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>initGlobalState()</span></span></code></pre></div><p>实现共享数据。</p><p>例如：</p><ul><li>用户信息</li><li>Token</li><li>权限</li></ul><hr><h3 id="event-bus" tabindex="-1"><strong>Event Bus</strong> <a class="header-anchor" href="#event-bus" aria-label="Permalink to &quot;**Event Bus**&quot;">​</a></h3><p>例如：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mitt</span></span></code></pre></div><p>发布订阅模式。</p><p>解耦程度高。</p><p>适合：跨应用通知。</p><hr><h3 id="浏览器通信能力" tabindex="-1"><strong>浏览器通信能力</strong> <a class="header-anchor" href="#浏览器通信能力" aria-label="Permalink to &quot;**浏览器通信能力**&quot;">​</a></h3><p>例如：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>postMessage</span></span>
<span class="line"><span>BroadcastChannel</span></span></code></pre></div><p>用于跨上下文通信。</p><hr><h3 id="共享-store" tabindex="-1"><strong>共享 Store</strong> <a class="header-anchor" href="#共享-store" aria-label="Permalink to &quot;**共享 Store**&quot;">​</a></h3><p>如 Redux / Pinia。</p><p>一般不推荐。</p><p>因为：容易造成强耦合。</p><hr><h2 id="_6-微前端如何共享登录态" tabindex="-1"><strong>6. 微前端如何共享登录态？</strong> <a class="header-anchor" href="#_6-微前端如何共享登录态" aria-label="Permalink to &quot;**6. 微前端如何共享登录态？**&quot;">​</a></h2><p><strong>高频。</strong></p><p>核心思路：</p><p>单点登录（SSO）。</p><p>一般做法：用户登录主系统后：</p><p>1.主应用获取：token</p><p>2.然后：通过 props 或全局状态注入子应用。</p><p>同域情况下：Cookie 自动共享。</p><p>跨域：通常：JWT + SSO，实现统一认证。</p><p>做到：一次登录，全站通用。</p><hr><h2 id="_7-qiankun-和-module-federation-有什么区别" tabindex="-1"><strong>7. qiankun 和 Module Federation 有什么区别？</strong> <a class="header-anchor" href="#_7-qiankun-和-module-federation-有什么区别" aria-label="Permalink to &quot;**7. qiankun 和 Module Federation 有什么区别？**&quot;">​</a></h2><p><strong>这是经典题。</strong></p><p><strong>核心区别：</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>qiankun</th><th>Module Federation</th></tr></thead><tbody><tr><td>粒度</td><td>应用级</td><td>模块级</td></tr><tr><td>目标</td><td>微前端</td><td>模块共享</td></tr><tr><td>隔离性</td><td>强</td><td>相对弱</td></tr><tr><td>部署</td><td>独立部署</td><td>联邦部署</td></tr><tr><td>场景</td><td>中后台拆分</td><td>组件共享</td></tr></tbody></table><p>简单说：</p><p>qiankun 更关注系统拆分。<br> Module Federation 更关注资源共享。</p><p>很多大型项目：</p><p>qiankun + Module Federation 混合。</p><p>例如：</p><p>子系统拆分用 qiankun，组件共享用 Module Federation。</p><hr><h2 id="_8-微前端有什么缺点" tabindex="-1"><strong>8. 微前端有什么缺点？</strong> <a class="header-anchor" href="#_8-微前端有什么缺点" aria-label="Permalink to &quot;**8. 微前端有什么缺点？**&quot;">​</a></h2><p><strong>高分回答一定要讲缺点。</strong></p><h3 id="性能问题" tabindex="-1"><strong>性能问题</strong> <a class="header-anchor" href="#性能问题" aria-label="Permalink to &quot;**性能问题**&quot;">​</a></h3><p>多个子应用：可能加载多个 runtime。</p><p>资源增多。首屏变慢。</p><hr><h3 id="通信复杂" tabindex="-1"><strong>通信复杂</strong> <a class="header-anchor" href="#通信复杂" aria-label="Permalink to &quot;**通信复杂**&quot;">​</a></h3><p>应用间状态同步困难。</p><p>容易：数据不一致。</p><hr><h3 id="调试复杂" tabindex="-1"><strong>调试复杂</strong> <a class="header-anchor" href="#调试复杂" aria-label="Permalink to &quot;**调试复杂**&quot;">​</a></h3><p>问题定位难。</p><p>可能涉及：</p><ul><li>主应用</li><li>子应用</li><li>沙箱</li></ul><p>排查成本高。</p><hr><h3 id="样式污染" tabindex="-1"><strong>样式污染</strong> <a class="header-anchor" href="#样式污染" aria-label="Permalink to &quot;**样式污染**&quot;">​</a></h3><p>CSS 冲突：</p><p>是高频问题。</p><p>需要：</p><ul><li>CSS Modules</li><li>Scoped</li><li>Shadow DOM</li></ul><p>隔离。</p><hr><h3 id="运维复杂" tabindex="-1"><strong>运维复杂</strong> <a class="header-anchor" href="#运维复杂" aria-label="Permalink to &quot;**运维复杂**&quot;">​</a></h3><p>部署链路变长。</p><p>CI/CD 更复杂。</p><hr><h2 id="_9-什么情况下不建议用微前端" tabindex="-1"><strong>9. 什么情况下不建议用微前端？</strong> <a class="header-anchor" href="#_9-什么情况下不建议用微前端" aria-label="Permalink to &quot;**9. 什么情况下不建议用微前端？**&quot;">​</a></h2><p><strong>这个题非常加分。</strong></p><p><strong>不要无脑说“都适合”。</strong></p><p><strong>以下场景：</strong></p><ol><li><strong>小团队</strong></li></ol><p>比如：5 人以内。系统不复杂。</p><p>微前端：治理成本 &gt; 收益。</p><ol start="2"><li><strong>强耦合业务</strong></li></ol><p>模块之间：共享状态很多，频繁通信。</p><p>拆分意义不大。</p><ol start="3"><li><strong>中小项目</strong></li></ol><p>几十个页面，单体应用足够，没必要过度设计。</p><hr><h2 id="_10-如果让你落地微前端-你怎么设计" tabindex="-1"><strong>10. 如果让你落地微前端，你怎么设计？</strong> <a class="header-anchor" href="#_10-如果让你落地微前端-你怎么设计" aria-label="Permalink to &quot;**10. 如果让你落地微前端，你怎么设计？**&quot;">​</a></h2><p><strong>面试高分答案：</strong></p><p><strong>我会先评估：</strong></p><p><strong>第一：业务边界</strong></p><p>是否天然拆分：</p><ul><li>用户中心</li><li>权限</li><li>订单</li></ul><p>做到：业务自治。</p><p><strong>第二：技术方案</strong></p><p>优先：qiankun</p><p>原因：成熟、生态稳定。</p><p><strong>第三：统一规范</strong></p><p>包括：</p><ul><li>登录态</li><li>路由规范</li><li>埋点</li><li>权限</li><li>UI 规范</li></ul><p>否则：容易变成技术灾难。</p><p><strong>第四：性能优化</strong></p><p>例如：</p><ul><li>prefetch</li><li>CDN</li><li>按需加载</li><li>shared dependency</li></ul><p>减少重复资源。</p><hr><p><strong>最后一句总结（适合面试收尾）：</strong></p><p><strong>微前端不是银弹，它更适合大型组织协作和复杂业务拆分。如果业务规模不足，治理成本可能高于收益，所以技术选型一定是收益、复杂度和团队能力之间的平衡。</strong></p><p><strong>这个表达会更像高级工程师/架构师。</strong></p><h1 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to &quot;性能优化&quot;">​</a></h1><h2 id="一、资源层优化-收益最高" tabindex="-1">一、资源层优化（收益最高） <a class="header-anchor" href="#一、资源层优化-收益最高" aria-label="Permalink to &quot;一、资源层优化（收益最高）&quot;">​</a></h2><h3 id="_1-依赖共享-避免重复打包" tabindex="-1">1. 依赖共享，避免重复打包 <a class="header-anchor" href="#_1-依赖共享-避免重复打包" aria-label="Permalink to &quot;1. 依赖共享，避免重复打包&quot;">​</a></h3><p>这是微前端最重要的优化之一。</p><p>问题在于：</p><p>多个子应用可能都依赖：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>react</span></span>
<span class="line"><span>react-dom</span></span>
<span class="line"><span>antd</span></span>
<span class="line"><span>lodash</span></span></code></pre></div><p>如果每个应用都独立打包：</p><p>同一个依赖会被重复下载。</p><p>例如：</p><p>三个 React 子应用：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>react × 3</span></span>
<span class="line"><span>react-dom × 3</span></span></code></pre></div><p>首屏资源体积会明显增大。</p><h3 id="优化方案" tabindex="-1">优化方案 <a class="header-anchor" href="#优化方案" aria-label="Permalink to &quot;优化方案&quot;">​</a></h3><h4 id="_1-externals-cdn" tabindex="-1">（1）externals + CDN <a class="header-anchor" href="#_1-externals-cdn" aria-label="Permalink to &quot;（1）externals + CDN&quot;">​</a></h4><p>把公共依赖抽离：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>externals: {</span></span>
<span class="line"><span>  react: &#39;React&#39;,</span></span>
<span class="line"><span>  &#39;react-dom&#39;: &#39;ReactDOM&#39;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>由主应用统一加载：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;script src=&quot;react.production.min.js&quot;&gt;&lt;/script&gt;</span></span></code></pre></div><p>这样：</p><p>所有子应用共享同一个 React 实例。</p><p>优点：</p><ul><li>降低 bundle 体积</li><li>加快加载速度</li></ul><p>缺点：</p><ul><li>依赖版本管理较复杂</li></ul><hr><h4 id="_2-module-federation-推荐" tabindex="-1">（2）Module Federation（推荐） <a class="header-anchor" href="#_2-module-federation-推荐" aria-label="Permalink to &quot;（2）Module Federation（推荐）&quot;">​</a></h4><p>基于：</p><p>Webpack 5。</p><p>实现运行时依赖共享：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>shared: {</span></span>
<span class="line"><span>  react: {</span></span>
<span class="line"><span>    singleton: true</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  &quot;react-dom&quot;: {</span></span>
<span class="line"><span>    singleton: true</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>核心思想：</p><p>多个应用共享同一份依赖。</p><p>避免重复下载与重复初始化。</p><p>相比 CDN：</p><p>更适合大型项目。</p><hr><h3 id="_2-静态资源缓存" tabindex="-1">2. 静态资源缓存 <a class="header-anchor" href="#_2-静态资源缓存" aria-label="Permalink to &quot;2. 静态资源缓存&quot;">​</a></h3><p>必须开启：</p><ul><li>强缓存</li><li>协商缓存</li></ul><p>例如：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cache-Control: max-age=31536000</span></span></code></pre></div><p>同时：</p><p>资源 hash 化：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main.a123.js</span></span></code></pre></div><p>这样：</p><p>用户二次访问几乎不需要重新下载静态资源。</p><hr><h3 id="_3-资源压缩" tabindex="-1">3. 资源压缩 <a class="header-anchor" href="#_3-资源压缩" aria-label="Permalink to &quot;3. 资源压缩&quot;">​</a></h3><p>开启：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gzip</span></span>
<span class="line"><span>brotli</span></span></code></pre></div><p>通常：</p><p>JS 体积可减少 50% 以上。</p><p>这是成本最低、收益最高的优化方式之一。</p><hr><h2 id="二、子应用加载优化" tabindex="-1">二、子应用加载优化 <a class="header-anchor" href="#二、子应用加载优化" aria-label="Permalink to &quot;二、子应用加载优化&quot;">​</a></h2><h3 id="_1-预加载-prefetch" tabindex="-1">1. 预加载（Prefetch） <a class="header-anchor" href="#_1-预加载-prefetch" aria-label="Permalink to &quot;1. 预加载（Prefetch）&quot;">​</a></h3><p>以：</p><p>qiankun 为例：</p><p>支持：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>start({</span></span>
<span class="line"><span>  prefetch: true</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>原理：</p><p>用户进入主系统后：</p><p>浏览器空闲时提前下载高频子应用资源。</p><p>例如：</p><p>用户访问：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/user</span></span></code></pre></div><p>后台提前加载：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/order</span></span>
<span class="line"><span>/product</span></span></code></pre></div><p>用户切换页面时：</p><p>几乎秒开。</p><p>但要注意：</p><p>不要全部预加载。</p><p>否则：</p><p>首屏压力过大。</p><p>建议：</p><p>只预加载高频业务模块。</p><hr><h3 id="_2-路由级懒加载" tabindex="-1">2. 路由级懒加载 <a class="header-anchor" href="#_2-路由级懒加载" aria-label="Permalink to &quot;2. 路由级懒加载&quot;">​</a></h3><p>不要登录后：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一次加载所有子应用</span></span></code></pre></div><p>正确做法：</p><p>按路由动态加载。</p><p>例如：</p><p>只有访问：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/order</span></span></code></pre></div><p>时：</p><p>才 mount 订单系统。</p><p>这样能显著降低：</p><p>首屏加载时间。</p><hr><h3 id="_3-子应用缓存-keepalive" tabindex="-1">3. 子应用缓存（KeepAlive） <a class="header-anchor" href="#_3-子应用缓存-keepalive" aria-label="Permalink to &quot;3. 子应用缓存（KeepAlive）&quot;">​</a></h3><p>微前端切换页面：</p><p>通常会：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mount → unmount → remount</span></span></code></pre></div><p>问题：</p><ul><li>页面闪烁</li><li>接口重复请求</li><li>表单状态丢失</li></ul><p>优化方案：</p><p>缓存子应用状态。</p><p>类似：</p><ul><li>Vue KeepAlive</li><li>React 页面缓存</li></ul><p>适用于：</p><ul><li>查询页</li><li>工作台</li><li>长表单</li></ul><p>体验提升非常明显。</p><hr><h2 id="三、运行时优化" tabindex="-1">三、运行时优化 <a class="header-anchor" href="#三、运行时优化" aria-label="Permalink to &quot;三、运行时优化&quot;">​</a></h2><h3 id="_1-减少重复初始化请求" tabindex="-1">1. 减少重复初始化请求 <a class="header-anchor" href="#_1-减少重复初始化请求" aria-label="Permalink to &quot;1. 减少重复初始化请求&quot;">​</a></h3><p>很多子应用进入页面都会请求：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户信息</span></span>
<span class="line"><span>权限</span></span>
<span class="line"><span>菜单</span></span>
<span class="line"><span>字典</span></span>
<span class="line"><span>国际化配置</span></span></code></pre></div><p>问题：</p><p>每个应用重复请求。</p><p>优化：</p><p>由主应用统一管理。</p><p>例如：</p><p>通过 props 或全局状态：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>props.userInfo</span></span>
<span class="line"><span>props.permission</span></span></code></pre></div><p>共享给子应用。</p><p>这样：</p><p>减少重复 IO 请求。</p><p>提升加载速度。</p><hr><h3 id="_2-减少沙箱开销" tabindex="-1">2. 减少沙箱开销 <a class="header-anchor" href="#_2-减少沙箱开销" aria-label="Permalink to &quot;2. 减少沙箱开销&quot;">​</a></h3><p>例如：</p><p>qiankun 使用：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ProxySandbox</span></span></code></pre></div><p>对：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>window</span></span></code></pre></div><p>做代理。</p><p>如果大量：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>window.xxx</span></span></code></pre></div><p>访问：</p><p>会增加运行时开销。</p><p>优化：</p><p>尽量使用模块内部状态，不滥用全局对象。</p><hr><h3 id="_3-防止内存泄漏" tabindex="-1">3. 防止内存泄漏 <a class="header-anchor" href="#_3-防止内存泄漏" aria-label="Permalink to &quot;3. 防止内存泄漏&quot;">​</a></h3><p>子应用销毁时：</p><p>必须清理：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eventListener</span></span>
<span class="line"><span>timer</span></span>
<span class="line"><span>websocket</span></span>
<span class="line"><span>observer</span></span></code></pre></div><p>否则：</p><p>频繁切换后：</p><p>页面越来越卡。</p><p>例如：</p><p>React：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>useEffect(() =&gt; {</span></span>
<span class="line"><span>  const timer = setInterval(() =&gt; {})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  return () =&gt; clearInterval(timer)</span></span>
<span class="line"><span>}, [])</span></span></code></pre></div><hr><h2 id="四、渲染层优化" tabindex="-1">四、渲染层优化 <a class="header-anchor" href="#四、渲染层优化" aria-label="Permalink to &quot;四、渲染层优化&quot;">​</a></h2><h3 id="_1-减少无效渲染" tabindex="-1">1. 减少无效渲染 <a class="header-anchor" href="#_1-减少无效渲染" aria-label="Permalink to &quot;1. 减少无效渲染&quot;">​</a></h3><p>React：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>memo</span></span>
<span class="line"><span>useMemo</span></span>
<span class="line"><span>useCallback</span></span></code></pre></div><p>Vue：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>v-memo</span></span></code></pre></div><p>目标：</p><p>避免整个子应用反复 render。</p><hr><h3 id="_2-长列表虚拟化" tabindex="-1">2. 长列表虚拟化 <a class="header-anchor" href="#_2-长列表虚拟化" aria-label="Permalink to &quot;2. 长列表虚拟化&quot;">​</a></h3><p>例如：</p><p>1000 条表格数据。</p><p>不要全部渲染。</p><p>使用：</p><ul><li>Virtual List</li><li>Windowing</li></ul><p>只渲染：</p><p>可视区域 DOM。</p><p>性能提升明显。</p><hr><h3 id="_3-骨架屏与-loading" tabindex="-1">3. 骨架屏与 Loading <a class="header-anchor" href="#_3-骨架屏与-loading" aria-label="Permalink to &quot;3. 骨架屏与 Loading&quot;">​</a></h3><p>用户感知优化。</p><p>子应用 mount 前：</p><p>显示：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skeleton</span></span>
<span class="line"><span>Loading</span></span></code></pre></div><p>减少：</p><p>白屏感知时间。</p><hr><h2 id="五、架构层优化-高阶" tabindex="-1">五、架构层优化（高阶） <a class="header-anchor" href="#五、架构层优化-高阶" aria-label="Permalink to &quot;五、架构层优化（高阶）&quot;">​</a></h2><h3 id="_1-控制拆分粒度" tabindex="-1">1. 控制拆分粒度 <a class="header-anchor" href="#_1-控制拆分粒度" aria-label="Permalink to &quot;1. 控制拆分粒度&quot;">​</a></h3><p>微前端不是拆得越细越好。</p><p>错误：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一个菜单一个应用</span></span></code></pre></div><p>会导致：</p><ul><li>通信复杂</li><li>切换成本高</li><li>性能下降</li></ul><p>建议：</p><p>按业务域拆分：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>订单中心</span></span>
<span class="line"><span>用户中心</span></span>
<span class="line"><span>营销中心</span></span></code></pre></div><p>做到：</p><p>高内聚、低耦合。</p><hr><h3 id="_2-主应用提供统一能力" tabindex="-1">2. 主应用提供统一能力 <a class="header-anchor" href="#_2-主应用提供统一能力" aria-label="Permalink to &quot;2. 主应用提供统一能力&quot;">​</a></h3><p>主应用统一管理：</p><ul><li>登录态</li><li>权限</li><li>埋点</li><li>国际化</li><li>UI SDK</li></ul><p>避免：</p><p>子应用重复建设。</p><hr><h3 id="_3-ssr-优化首屏" tabindex="-1">3. SSR 优化首屏 <a class="header-anchor" href="#_3-ssr-优化首屏" aria-label="Permalink to &quot;3. SSR 优化首屏&quot;">​</a></h3><p>对于首屏敏感业务：</p><p>可以结合：</p><p>Next.js</p><p>做 SSR。</p><p>减少：</p><p>首屏白屏时间。</p><p>尤其：</p><p>ToC 场景收益明显。</p><hr><h2 id="面试收尾总结-推荐背诵" tabindex="-1">面试收尾总结（推荐背诵） <a class="header-anchor" href="#面试收尾总结-推荐背诵" aria-label="Permalink to &quot;面试收尾总结（推荐背诵）&quot;">​</a></h2><p>微前端性能优化我通常会从五个层面考虑：资源层避免依赖重复加载，比如通过 Module Federation 做共享；加载层通过 prefetch、懒加载和应用缓存减少切换成本；运行时减少重复初始化和沙箱开销，同时避免内存泄漏；渲染层通过 memo、虚拟列表减少渲染压力；最后在架构层控制拆分粒度，避免过度微前端化。本质上微前端优化的核心是减少重复加载、降低初始化成本以及控制运行时复杂度。</p>`,482)])])}const g=p(i,[["render",t]]);export{u as __pageData,g as default};
